INSERT INTO cast (movie_id, person_id, name, character_name, profile_path) VALUES
(#{movieId}, #{cast.id}, #{cast.name}, #{cast.characterName}, #{cast.profilePath})
ON DUPLICATE KEY UPDATE name = VALUES(name), character_name = VALUES(character_name), profile_path = VALUES(profile_path);

INSERT INTO crew (movie_id, person_id, name, job, profile_path) VALUES
(#{movieId}, #{crew.id}, #{crew.name}, #{crew.job}, #{crew.profilePath})
ON DUPLICATE KEY UPDATE name = VALUES(name), job = VALUES(job), profile_path = VALUES(profile_path);
